def _to_decimal(value: Any) -> Decimal:
    if isinstance(value, Decimal):
        return value
    try:
        return Decimal(str(value))
    except Exception as e:
        raise ValidationError(f"Invalid numeric value: {value!r}") from e


def _money(value: Decimal, currency: str = "USD") -> Decimal:
    quant = Decimal("0.01") if currency.upper() not in {"JPY", "KRW"} else Decimal("1")
    return value.quantize(quant, rounding=ROUND_HALF_UP)


def _get_discount_rate(role: str) -> Decimal:
    role_norm = (role or "").strip().lower()
    if role_norm == "enterprise":
        return Decimal("0.30")
    if role_norm == "premium":
        return Decimal("0.15")
    if role_norm == "basic":
        return Decimal("0.00")
    raise ValidationError(f"Unknown user role: {role!r}")


def _validate_cart_items(cart_items: List[Any]) -> List[CartItem]:
    if not isinstance(cart_items, list) or not cart_items:
        raise ValidationError("cart_items must be a non-empty list")

    normalized: List[CartItem] = []
    for idx, item in enumerate(cart_items):
        if isinstance(item, CartItem):
            ci = item
        elif isinstance(item, dict):
            if "unit_price" not in item:
                raise ValidationError(f"Cart item at index {idx} missing 'unit_price'")
            ci = CartItem(
                name=str(item.get("name", f"item_{idx}")),
                unit_price=_to_decimal(item["unit_price"]),
                quantity=int(item.get("quantity", 1)),
            )
        else:
            raise ValidationError(f"Cart item at index {idx} must be CartItem or dict")

        if ci.quantity <= 0:
            raise ValidationError(f"Cart item at index {idx} has invalid quantity: {ci.quantity}")
        if ci.unit_price < 0:
            raise ValidationError(f"Cart item at index {idx} has negative unit_price: {ci.unit_price}")

        normalized.append(ci)

    return normalized


def _validate_payment_details(payment_details: Dict[str, Any]) -> Dict[str, Any]:
    if not isinstance(payment_details, dict):
        raise ValidationError("payment_details must be a dict")

    method = str(payment_details.get("method", "")).strip().lower()
    if method not in {"card", "bank_transfer", "wallet"}:
        raise ValidationError("payment_details.method must be one of: card, bank_transfer, wallet")

    currency = str(payment_details.get("currency", "USD")).strip().upper()
    if not currency:
        raise ValidationError("payment_details.currency is required")

    return {
        "method": method,
        "currency": currency,
        "idempotency_key": payment_details.get("idempotency_key"),
        "metadata": payment_details.get("metadata") or {},
        "raw": payment_details,
    }


def _process_payment(amount: Decimal, payment_details: Dict[str, Any]) -> Dict[str, Any]:
    if amount <= 0:
        raise PaymentError("Charge amount must be greater than 0")

    return {
        "status": "succeeded",
        "amount_charged": str(amount),
        "currency": payment_details["currency"],
        "payment_method": payment_details["method"],
        "transaction_id": f"txn_{abs(hash((str(amount), payment_details.get('idempotency_key'))))}",
    }


def process_payment_with_role_discount(
    user: Any,
    cart_items: List[Any],
    payment_details: Dict[str, Any],
) -> Dict[str, Any]:
    if user is None or not hasattr(user, "role"):
        raise ValidationError("user must have a 'role' field")

    role = getattr(user, "role")
    discount_rate = _get_discount_rate(role)

