    subtotal = _money(subtotal, pd["currency"])

    discount_amount = _money(subtotal * discount_rate, pd["currency"])
    total = _money(subtotal - discount_amount, pd["currency"])

    payment_result = _process_payment(total, pd)

    return {
        "user_role": str(role).strip().lower(),
        "discount_rate": str(discount_rate),
        "subtotal": str(subtotal),
        "discount_amount": str(discount_amount),
        "total": str(total),
        "currency": pd["currency"],
        "payment": payment_result,
        "items": [
            {
                "name": i.name,
                "unit_price": str(_money(_to_decimal(i.unit_price), pd["currency"])),
                "quantity": i.quantity,
                "line_total": str(_money(_to_decimal(i.unit_price) * i.quantity, pd["currency"])),
            }
            for i in items
        ],
    }